const _origin_fetch = window.fetch;
// @ts-ignore
let _proxy_fetch: typeof fetch | null = null;

function getProxyFetch({ onRequest, onResponse, onError }: ProxyOptions) {
    return async function (...args: Parameters<typeof fetch>): Promise<Response> {
        let res;
        try {
            if (onRequest) {
                args = await onRequest(...args);
            }
            res = await _origin_fetch(...args);
            if (onResponse) {
                res = await onResponse(res);
            }
        } catch (error) {
            onError && onError(error);
        } finally {
            return res as Response;
        }
    };
}

export function proxyFetch(proxyOptions: ProxyOptions) {
    // eslint-disable-next-line no-multi-assign
    window.fetch = _proxy_fetch = _proxy_fetch ?? getProxyFetch(proxyOptions);
}

interface ProxyOptions {
    onRequest?: (...args: Parameters<typeof fetch>) => Promise<Parameters<typeof fetch>>;
    onResponse?: (res: Response) => Promise<Response>;
    onError?: (error: any) => void;
}

export function unproxyFetch() {
    window.fetch = _origin_fetch;
}
